#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int* calculateAssignments(int** tree, int* subtreeSizes, int node, int N) {
    int* assignments = (int*) malloc(2 * sizeof(int));
    if (subtreeSizes[node] == 1) {
        assignments[0] = 1;
        assignments[1] = 1;
        return assignments;
    }
    int totalAssignments = 1;
    for (int i = 0; i < tree[node][0]; i++) {
        int child = tree[node][i + 1];
        int* childAssignments = calculateAssignments(tree, subtreeSizes, child, N);
        totalAssignments = (totalAssignments * (childAssignments[0] + childAssignments[1])) % MOD;
    }
    assignments[0] = totalAssignments;
    totalAssignments = 1;
    for (int i = 0; i < tree[node][0]; i++) {
        int child = tree[node][i + 1];
        int* childAssignments = calculateAssignments(tree, subtreeSizes, child, N);
        totalAssignments = (totalAssignments * childAssignments[1]) % MOD;
    }
    assignments[1] = totalAssignments;
    return assignments;
}

int main() {
    int N;
    scanf("%d", &N);
    int** tree = (int**) malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        tree[i] = (int*) malloc(2 * sizeof(int));
        tree[i][0] = 0;
    }
    for (int i = 1; i < N; i++) {
        int parent;
        scanf("%d", &parent);
        parent--;
        tree[parent][0]++;
        tree[parent] = (int*) realloc(tree[parent], (tree[parent][0] + 1) * sizeof(int));
        tree[parent][tree[parent][0]] = i;
    }
    int* subtreeSizes = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        subtreeSizes[i] = 1;
    }
    for (int i = N - 1; i >= 0; i--) {
        for (int j = 0; j < tree[i][0]; j++) {
            int child = tree[i][j + 1];
            subtreeSizes[i] += subtreeSizes[child];
        }
    }
    int* assignments = calculateAssignments(tree, subtreeSizes, 0, N);
    printf("%d\n", (assignments[0] + assignments[1]) % MOD);
    return 0;
}

