#include <iostream>
#include <vector>
using namespace std;
#define MOD 1000000007

typedef long long ll;

ll calculateAssignments(vector<vector<int>>& tree, vector<int>& subtreeSizes, int node) {
    if (subtreeSizes[node] == 1) {
        return 2;
    }
    ll totalAssignments = 1;
    for (int child : tree[node]) {
        totalAssignments = (totalAssignments * calculateAssignments(tree, subtreeSizes, child)) % MOD;
    }
    return totalAssignments;
}

int main() {
    int N;
    cin >> N;
    vector<vector<int>> tree(N);
    for (int i = 1; i < N; i++) {
        int parent;
        cin >> parent;
        parent--;
        tree[parent].push_back(i);
    }
    vector<int> subtreeSizes(N, 1);
    for (int i = N - 1; i >= 0; i--) {
        for (int child : tree[i]) {
            subtreeSizes[i] += subtreeSizes[child];
        }
    }
    ll assignments = calculateAssignments(tree, subtreeSizes, 0);
    cout << assignments % MOD << endl;
    return 0;
}

