import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[][] tree = new int[N][2];
        for (int i = 0; i < N; i++) {
            tree[i][0] = 0;
        }
        for (int i = 1; i < N; i++) {
            int parent = scanner.nextInt() - 1;
            tree[parent][0]++;
            tree[parent][tree[parent][0]] = i;
        }
        int[] subtreeSizes = new int[N];
        for (int i = 0; i < N; i++) {
            subtreeSizes[i] = 1;
        }
        for (int i = N - 1; i >= 0; i--) {
            for (int j = 0; j < tree[i][0]; j++) {
                int child = tree[i][j + 1];
                subtreeSizes[i] += subtreeSizes[child];
            }
        }
        long assignments = calculateAssignments(tree, subtreeSizes, 0, N);
        System.out.println(assignments % MOD);
    }
    public static long calculateAssignments(int[][] tree, int[] subtreeSizes, int node, int N) {
        if (subtreeSizes[node] == 1) {
            return 2;
        }
        long totalAssignments = 1;
        for (int i = 0; i < tree[node][0]; i++) {
            int child = tree[node][i + 1];
            totalAssignments = (totalAssignments * calculateAssignments(tree, subtreeSizes, child, N)) % MOD;
        }
        return totalAssignments;
    }
}

