import sys
MOD = 1000000007

def calculate_assignments(tree, subtree_sizes, node):
    if subtree_sizes[node] == 1:
        return 2
    total_assignments = 1
    for child in tree[node]:
        total_assignments = (total_assignments * calculate_assignments(tree, subtree_sizes, child)) % MOD
    return total_assignments

def main():
    N = int(sys.stdin.readline().strip())
    tree = [[] for _ in range(N)]
    for i in range(1, N):
        parent = int(sys.stdin.readline().strip()) - 1
        tree[parent].append(i)
    subtree_sizes = [1] * N
    for i in range(N - 1, -1, -1):
        for child in tree[i]:
            subtree_sizes[i] += subtree_sizes[child]
    assignments = calculate_assignments(tree, subtree_sizes, 0)
    print(assignments % MOD)
if __name__ == '__main__':
    main()

